450	function resolveChatChannelSecurity<TResolvedAccount extends { accountId?: string | null }>(
451	  security:
452	    | ChannelSecurityAdapter<TResolvedAccount>
453	    | ChatChannelSecurityOptions<TResolvedAccount>
454	    | undefined,
455	): ChannelSecurityAdapter<TResolvedAccount> | undefined {
456	  if (!security) {
457	    return undefined;
458	  }
459	  if (!("dm" in security)) {
460	    return security;
461	  }
462	  return {
463	    resolveDmPolicy: ({ cfg, accountId, account }) =>
464	      buildAccountScopedDmSecurityPolicy({
465	        cfg,
466	        channelKey: security.dm.channelKey,
467	        accountId,
468	        fallbackAccountId: security.dm.resolveFallbackAccountId?.(account) ?? account.accountId,
469	        policy: security.dm.resolvePolicy(account),
470	        allowFrom: security.dm.resolveAllowFrom(account) ?? [],
471	        defaultPolicy: security.dm.defaultPolicy,
472	        allowFromPathSuffix: security.dm.allowFromPathSuffix,
473	        policyPathSuffix: security.dm.policyPathSuffix,
474	        approveChannelId: security.dm.approveChannelId,
475	        approveHint: security.dm.approveHint,
476	        normalizeEntry: security.dm.normalizeEntry,
477	      }),
478	    ...(security.collectWarnings ? { collectWarnings: security.collectWarnings } : {}),
479	  };
480	}
