## 5. INBOUND MESSAGE HANDLING

**Key Pattern** (from IRC):

```typescript
export async function handlePulseBoardInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  config: CoreConfig;
  runtime: RuntimeEnv;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<void> {
  const core = getPulseBoardRuntime();
  const pairing = createChannelPairingController({
    core,
    channel: "pulseboard",
    accountId: account.accountId,
  });

  // 1. Check DM policy (pairing/allowlist/open/disabled)
  const dmPolicy = account.config.dmPolicy ?? "pairing";
  const allowFrom = account.config.allowFrom ?? [];

  // 2. Resolve sender access
  const access = await resolveInboundDmAccess({
    channel: "pulseboard",
    accountId: account.accountId,
    dmPolicy,
    allowFrom,
    senderId: message.senderId,
    rawBody: message.text,
  });

  if (access.decision !== "allow") {
    return; // Drop message
  }

  // 3. Dispatch to agent/handler
  await dispatchInboundDm({
    cfg: config,
    channel: "pulseboard",
    accountId: account.accountId,
    peer: { kind: "direct", id: message.senderId },
    senderId: message.senderId,
    rawBody: message.text,
    messageId: message.messageId,
    timestamp: message.timestamp,
    deliver: async (payload) => {
      // Send reply
      await sendMessagePulseBoard(message.senderId, payload.text);
    },
  });
}
```

