## 6. OUTBOUND MESSAGE SENDING

**Key Pattern** (from Nostr):

```typescript
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error("PulseBoard is not configured (need apiKey in channels.pulseboard)");
  }

  // Apply text formatting
  const tableMode = runtime.channel.text.resolveMarkdownTableMode({
    cfg,
    channel: "pulseboard",
    accountId: account.accountId,
  });
  const message = runtime.channel.text.convertMarkdownTables(text, tableMode);

  // Send via API
  const response = await fetch(`${account.baseUrl}/api/messages`, {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${account.apiKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ to, text: message }),
  });

  if (!response.ok) {
    throw new Error(`PulseBoard API error: ${response.status}`);
  }

  const result = await response.json() as { id: string };
  return { messageId: result.id, to };
}
```

