105	export function createPreCryptoDirectDmAuthorizer(params: {
106	  resolveAccess: (
107	    senderId: string,
108	  ) => Promise<Pick<ResolvedInboundDirectDmAccess, "access"> | ResolvedInboundDirectDmAccess>;
