110	    senderId: string;
111	    reply: (text: string) => Promise<void>;
112	  }) => Promise<void>;
113	  onBlocked?: (params: {
114	    senderId: string;
115	    reason: string;
116	    reasonCode: DmGroupAccessReasonCode;
117	  }) => void;
118	}) {
119	  return async (input: {
120	    senderId: string;
121	    reply: (text: string) => Promise<void>;
122	  }): Promise<"allow" | "block" | "pairing"> => {
123	    const resolved = await params.resolveAccess(input.senderId);
124	    const access = "access" in resolved ? resolved.access : resolved;
125	    if (access.decision === "allow") {
126	      return "allow";
