32	}): TAccount {
33	  const hasExplicitAccountId = Boolean(params.accountId?.trim());
34	  const normalizedAccountId = params.normalizeAccountId(params.accountId);
35	  const primary = params.resolvePrimary(normalizedAccountId);
36	  if (hasExplicitAccountId || params.hasCredential(primary)) {
37	    return primary;
38	  }
39	
40	  const fallbackId = params.resolveDefaultAccountId();
41	  if (fallbackId === normalizedAccountId) {
42	    return primary;
43	  }
44	  const fallback = params.resolvePrimary(fallbackId);
45	  if (!params.hasCredential(fallback)) {
46	    return primary;
47	  }
48	  return fallback;
