1	import type { FinalizedMsgContext } from "../auto-reply/templating.js";
2	import type { ChannelId } from "../channels/plugins/types.js";
3	import type { OpenClawConfig } from "../config/config.js";
4	import {
5	  readStoreAllowFromForDmPolicy,
6	  resolveDmGroupAccessWithLists,
7	  type DmGroupAccessReasonCode,
8	} from "../security/dm-policy-shared.js";
9	import { resolveInboundRouteEnvelopeBuilderWithRuntime } from "./inbound-envelope.js";
10	import { recordInboundSessionAndDispatchReply } from "./inbound-reply-dispatch.js";
11	import type { OutboundReplyPayload } from "./reply-payload.js";
12	
13	export type DirectDmCommandAuthorizationRuntime = {
14	  shouldComputeCommandAuthorized: (rawBody: string, cfg: OpenClawConfig) => boolean;
15	  resolveCommandAuthorizedFromAuthorizers: (params: {
16	    useAccessGroups: boolean;
17	    authorizers: Array<{ configured: boolean; allowed: boolean }>;
18	    modeWhenAccessGroupsOff?: "allow" | "deny" | "configured";
19	  }) => boolean;
20	};
21	
22	export type ResolvedInboundDirectDmAccess = {
23	  access: {
24	    decision: "allow" | "block" | "pairing";
25	    reasonCode: DmGroupAccessReasonCode;
26	    reason: string;
27	    effectiveAllowFrom: string[];
28	  };
29	  shouldComputeAuth: boolean;
30	  senderAllowedForCommands: boolean;
31	  commandAuthorized: boolean | undefined;
32	};
33	
34	/** Resolve direct-DM policy, effective allowlists, and optional command auth in one place. */
35	export async function resolveInboundDirectDmAccessWithRuntime(params: {
36	  cfg: OpenClawConfig;
37	  channel: ChannelId;
38	  accountId: string;
39	  dmPolicy?: string | null;
40	  allowFrom?: Array<string | number> | null;
41	  senderId: string;
42	  rawBody: string;
43	  isSenderAllowed: (senderId: string, allowFrom: string[]) => boolean;
44	  runtime: DirectDmCommandAuthorizationRuntime;
45	  modeWhenAccessGroupsOff?: "allow" | "deny" | "configured";
46	  readStoreAllowFrom?: (provider: ChannelId, accountId: string) => Promise<string[]>;
47	}): Promise<ResolvedInboundDirectDmAccess> {
48	  const dmPolicy = params.dmPolicy ?? "pairing";
49	  const storeAllowFrom =
50	    dmPolicy === "pairing"
51	      ? await readStoreAllowFromForDmPolicy({
52	          provider: params.channel,
53	          accountId: params.accountId,
54	          dmPolicy,
55	          readStore: params.readStoreAllowFrom,
56	        })
57	      : [];
58	
59	  const access = resolveDmGroupAccessWithLists({
60	    isGroup: false,
61	    dmPolicy,
62	    allowFrom: params.allowFrom,
63	    storeAllowFrom,
64	    groupAllowFromFallbackToAllowFrom: false,
65	    isSenderAllowed: (allowEntries) => params.isSenderAllowed(params.senderId, allowEntries),
66	  });
67	
68	  const shouldComputeAuth = params.runtime.shouldComputeCommandAuthorized(
69	    params.rawBody,
70	    params.cfg,
71	  );
72	  const senderAllowedForCommands = params.isSenderAllowed(
73	    params.senderId,
74	    access.effectiveAllowFrom,
75	  );
76	  const commandAuthorized = shouldComputeAuth
77	    ? dmPolicy === "open"
78	      ? true
79	      : params.runtime.resolveCommandAuthorizedFromAuthorizers({
80	          useAccessGroups: params.cfg.commands?.useAccessGroups !== false,
81	          authorizers: [
82	            {
83	              configured: access.effectiveAllowFrom.length > 0,
84	              allowed: senderAllowedForCommands,
85	            },
86	          ],
87	          modeWhenAccessGroupsOff: params.modeWhenAccessGroupsOff,
88	        })
89	    : undefined;
90	
91	  return {
92	    access: {
93	      decision: access.decision,
94	      reasonCode: access.reasonCode,
95	      reason: access.reason,
96	      effectiveAllowFrom: access.effectiveAllowFrom,
97	    },
98	    shouldComputeAuth,
99	    senderAllowedForCommands,
100	    commandAuthorized,
101	  };
102	}
103	
104	/** Convert resolved DM policy into a pre-crypto allow/block/pairing callback. */
105	export function createPreCryptoDirectDmAuthorizer(params: {
106	  resolveAccess: (
107	    senderId: string,
108	  ) => Promise<Pick<ResolvedInboundDirectDmAccess, "access"> | ResolvedInboundDirectDmAccess>;
109	  issuePairingChallenge?: (params: {
110	    senderId: string;
111	    reply: (text: string) => Promise<void>;
112	  }) => Promise<void>;
113	  onBlocked?: (params: {
114	    senderId: string;
115	    reason: string;
116	    reasonCode: DmGroupAccessReasonCode;
117	  }) => void;
118	}) {
119	  return async (input: {
120	    senderId: string;
121	    reply: (text: string) => Promise<void>;
122	  }): Promise<"allow" | "block" | "pairing"> => {
123	    const resolved = await params.resolveAccess(input.senderId);
124	    const access = "access" in resolved ? resolved.access : resolved;
125	    if (access.decision === "allow") {
126	      return "allow";
127	    }
128	    if (access.decision === "pairing") {
129	      if (params.issuePairingChallenge) {
130	        await params.issuePairingChallenge({
131	          senderId: input.senderId,
132	          reply: input.reply,
133	        });
134	      }
135	      return "pairing";
136	    }
137	    params.onBlocked?.({
138	      senderId: input.senderId,
139	      reason: access.reason,
140	      reasonCode: access.reasonCode,
141	    });
142	    return "block";
143	  };
144	}
145	
146	export type DirectDmPreCryptoGuardPolicy = {
147	  allowedKinds: readonly number[];
148	  maxFutureSkewSec: number;
149	  maxCiphertextBytes: number;
150	  maxPlaintextBytes: number;
151	  rateLimit: {
152	    windowMs: number;
153	    maxPerSenderPerWindow: number;
154	    maxGlobalPerWindow: number;
155	    maxTrackedSenderKeys: number;
156	  };
157	};
158	
159	export type DirectDmPreCryptoGuardPolicyOverrides = Partial<
160	  Omit<DirectDmPreCryptoGuardPolicy, "rateLimit">
161	> & {
162	  rateLimit?: Partial<DirectDmPreCryptoGuardPolicy["rateLimit"]>;
163	};
164	
165	/** Shared policy object for DM-style pre-crypto guardrails. */
166	export function createDirectDmPreCryptoGuardPolicy(
167	  overrides: DirectDmPreCryptoGuardPolicyOverrides = {},
168	): DirectDmPreCryptoGuardPolicy {
169	  return {
170	    allowedKinds: overrides.allowedKinds ?? [4],
171	    maxFutureSkewSec: overrides.maxFutureSkewSec ?? 120,
172	    maxCiphertextBytes: overrides.maxCiphertextBytes ?? 16 * 1024,
173	    maxPlaintextBytes: overrides.maxPlaintextBytes ?? 8 * 1024,
174	    rateLimit: {
175	      windowMs: overrides.rateLimit?.windowMs ?? 60_000,
176	      maxPerSenderPerWindow: overrides.rateLimit?.maxPerSenderPerWindow ?? 20,
177	      maxGlobalPerWindow: overrides.rateLimit?.maxGlobalPerWindow ?? 200,
178	      maxTrackedSenderKeys: overrides.rateLimit?.maxTrackedSenderKeys ?? 4096,
179	    },
180	  };
181	}
182	
183	type DirectDmRoutePeer = {
184	  kind: "direct";
185	  id: string;
186	};
187	
188	type DirectDmRoute = {
189	  agentId: string;
190	  sessionKey: string;
191	  accountId?: string;
192	};
193	
194	type DirectDmRuntime = {
195	  channel: {
196	    routing: {
197	      resolveAgentRoute: (params: {
198	        cfg: OpenClawConfig;
199	        channel: string;
200	        accountId: string;
201	        peer: DirectDmRoutePeer;
202	      }) => DirectDmRoute;
203	    };
204	    session: {
205	      resolveStorePath: typeof import("../config/sessions.js").resolveStorePath;
206	      readSessionUpdatedAt: (params: {
207	        storePath: string;
208	        sessionKey: string;
209	      }) => number | undefined;
210	      recordInboundSession: typeof import("../channels/session.js").recordInboundSession;
211	    };
212	    reply: {
213	      resolveEnvelopeFormatOptions: (
214	        cfg: OpenClawConfig,
215	      ) => ReturnType<typeof import("../auto-reply/envelope.js").resolveEnvelopeFormatOptions>;
216	      formatAgentEnvelope: typeof import("../auto-reply/envelope.js").formatAgentEnvelope;
217	      finalizeInboundContext: typeof import("../auto-reply/reply/inbound-context.js").finalizeInboundContext;
218	      dispatchReplyWithBufferedBlockDispatcher: typeof import("../auto-reply/reply/provider-dispatcher.js").dispatchReplyWithBufferedBlockDispatcher;
219	    };
220	  };
221	};
222	
223	/** Route, envelope, record, and dispatch one direct-DM turn through the standard pipeline. */
224	export async function dispatchInboundDirectDmWithRuntime(params: {
225	  cfg: OpenClawConfig;
226	  runtime: DirectDmRuntime;
227	  channel: string;
228	  channelLabel: string;
229	  accountId: string;
230	  peer: DirectDmRoutePeer;
231	  senderId: string;
232	  senderAddress: string;
233	  recipientAddress: string;
234	  conversationLabel: string;
235	  rawBody: string;
236	  messageId: string;
237	  timestamp?: number;
238	  commandAuthorized?: boolean;
239	  bodyForAgent?: string;
240	  commandBody?: string;
241	  provider?: string;
242	  surface?: string;
243	  originatingChannel?: string;
244	  originatingTo?: string;
245	  extraContext?: Record<string, unknown>;
246	  deliver: (payload: OutboundReplyPayload) => Promise<void>;
247	  onRecordError: (err: unknown) => void;
248	  onDispatchError: (err: unknown, info: { kind: string }) => void;
249	}): Promise<{
250	  route: DirectDmRoute;
251	  storePath: string;
252	  ctxPayload: FinalizedMsgContext;
253	}> {
254	  const { route, buildEnvelope } = resolveInboundRouteEnvelopeBuilderWithRuntime({
255	    cfg: params.cfg,
256	    channel: params.channel,
257	    accountId: params.accountId,
258	    peer: params.peer,
259	    runtime: params.runtime.channel,
260	    sessionStore: params.cfg.session?.store,
261	  });
262	
263	  const { storePath, body } = buildEnvelope({
264	    channel: params.channelLabel,
265	    from: params.conversationLabel,
266	    body: params.rawBody,
267	    timestamp: params.timestamp,
268	  });
269	
270	  const ctxPayload = params.runtime.channel.reply.finalizeInboundContext({
271	    Body: body,
272	    BodyForAgent: params.bodyForAgent ?? params.rawBody,
273	    RawBody: params.rawBody,
274	    CommandBody: params.commandBody ?? params.rawBody,
275	    From: params.senderAddress,
276	    To: params.recipientAddress,
277	    SessionKey: route.sessionKey,
278	    AccountId: route.accountId ?? params.accountId,
279	    ChatType: "direct",
280	    ConversationLabel: params.conversationLabel,
281	    SenderId: params.senderId,
282	    Provider: params.provider ?? params.channel,
283	    Surface: params.surface ?? params.channel,
284	    MessageSid: params.messageId,
285	    MessageSidFull: params.messageId,
286	    Timestamp: params.timestamp,
287	    CommandAuthorized: params.commandAuthorized,
288	    OriginatingChannel: params.originatingChannel ?? params.channel,
289	    OriginatingTo: params.originatingTo ?? params.recipientAddress,
290	    ...params.extraContext,
291	  });
292	
293	  await recordInboundSessionAndDispatchReply({
294	    cfg: params.cfg,
295	    channel: params.channel,
296	    accountId: route.accountId ?? params.accountId,
297	    agentId: route.agentId,
298	    routeSessionKey: route.sessionKey,
299	    storePath,
300	    ctxPayload,
301	    recordInboundSession: params.runtime.channel.session.recordInboundSession,
302	    dispatchReplyWithBufferedBlockDispatcher:
303	      params.runtime.channel.reply.dispatchReplyWithBufferedBlockDispatcher,
304	    deliver: params.deliver,
305	    onRecordError: params.onRecordError,
306	    onDispatchError: params.onDispatchError,
307	  });
308	
309	  return {
310	    route,
311	    storePath,
312	    ctxPayload,
313	  };
314	}
315	

