267	export function formatConfigWriteDeniedMessage(params: {
268	  result: Exclude<ConfigWriteAuthorizationResult, { allowed: true }>;
269	  fallbackChannelId?: string | null;
270	}): string {
271	  if (params.result.reason === "ambiguous-target") {
272	    return "⚠️ Channel-initiated /config writes cannot replace channels, channel roots, or accounts collections. Use a more specific path or gateway operator.admin.";
273	  }
274	
275	  const blocked = params.result.blockedScope?.scope;
276	  const channelLabel = blocked?.channelId ?? params.fallbackChannelId ?? "this channel";
277	  const hint = blocked?.channelId
278	    ? blocked.accountId
279	      ? `channels.${blocked.channelId}.accounts.${blocked.accountId}.configWrites=true`
280	      : `channels.${blocked.channelId}.configWrites=true`
281	    : params.fallbackChannelId
282	      ? `channels.${params.fallbackChannelId}.configWrites=true`
283	      : "channels.<channel>.configWrites=true";
284	  return `⚠️ Config writes are disabled for ${channelLabel}. Set ${hint} to enable.`;
285	}
