340	export function createScopedAccountConfigAccessors<
341	  ResolvedAccount,
342	  Config extends OpenClawConfig = OpenClawConfig,
343	>(params: {
344	  resolveAccount: (params: { cfg: Config; accountId?: string | null }) => ResolvedAccount;
345	  resolveAllowFrom: (account: ResolvedAccount) => Array<string | number> | null | undefined;
346	  formatAllowFrom: (allowFrom: Array<string | number>) => string[];
347	  resolveDefaultTo?: (account: ResolvedAccount) => string | number | null | undefined;
348	}): Pick<
349	  ChannelConfigAdapter<ResolvedAccount>,
350	  "resolveAllowFrom" | "formatAllowFrom" | "resolveDefaultTo"
351	> {
352	  const base = {
353	    resolveAllowFrom({ cfg, accountId }: { cfg: OpenClawConfig; accountId?: string | null }) {
354	      return mapAllowFromEntries(
355	        params.resolveAllowFrom(params.resolveAccount({ cfg: cfg as Config, accountId })),
356	      );
357	    },
358	    formatAllowFrom({ allowFrom }: { allowFrom: Array<string | number> }) {
359	      return params.formatAllowFrom(allowFrom);
360	    },
361	  };
362	
363	  if (!params.resolveDefaultTo) {
364	    return base;
365	  }
366	
367	  return {
368	    ...base,
369	    resolveDefaultTo({ cfg, accountId }) {
370	      return resolveOptionalConfigString(
371	        params.resolveDefaultTo?.(params.resolveAccount({ cfg: cfg as Config, accountId })),
372	      );
373	    },
374	  };
375	}
