557	function setTopLevelChannelEnabledInConfigSection<Config extends OpenClawConfig>(params: {
558	  cfg: Config;
559	  sectionKey: string;
560	  enabled: boolean;
561	}): Config {
562	  const section = params.cfg.channels?.[params.sectionKey] as Record<string, unknown> | undefined;
563	  return {
564	    ...params.cfg,
565	    channels: {
566	      ...params.cfg.channels,
567	      [params.sectionKey]: {
568	        ...section,
569	        enabled: params.enabled,
570	      },
571	    },
572	  } as Config;
573	}
574	
575	function removeTopLevelChannelConfigSection<Config extends OpenClawConfig>(params: {
576	  cfg: Config;
577	  sectionKey: string;
578	}): Config {
579	  const nextChannels = { ...params.cfg.channels } as Record<string, unknown>;
580	  delete nextChannels[params.sectionKey];
581	  const nextCfg = { ...params.cfg };
582	  if (Object.keys(nextChannels).length > 0) {
583	    nextCfg.channels = nextChannels as Config["channels"];
584	  } else {
585	    delete nextCfg.channels;
586	  }
587	  return nextCfg;
588	}
589	
590	function clearTopLevelChannelConfigFields<Config extends OpenClawConfig>(params: {
591	  cfg: Config;
592	  sectionKey: string;
593	  clearBaseFields: string[];
594	}): Config {
595	  const section = params.cfg.channels?.[params.sectionKey] as Record<string, unknown> | undefined;
596	  if (!section) {
597	    return params.cfg;
598	  }
599	  const nextSection = { ...section };
600	  for (const field of params.clearBaseFields) {
601	    delete nextSection[field];
602	  }
603	  return {
604	    ...params.cfg,
605	    channels: {
606	      ...params.cfg.channels,
607	      [params.sectionKey]: nextSection,
608	    },
609	  } as Config;
610	}
