/**
 * Normalize a PulseBoard target string to its canonical form.
 *
 * Canonical forms:
 *  - Board (group): `#board-name`  — the `#` prefix is preserved
 *  - User  (DM):    `username`     — any leading `@` is stripped
 *
 * Additionally strips an optional `pulseboard:` channel prefix.
 */
export function normalizePulseBoardTarget(raw: string): string {
  let target = raw.trim();

  // Strip optional channel prefix (e.g. "pulseboard:#news" or "pulseboard:alice")
  target = target.replace(/^pulseboard:/i, "").trim();

  // @username → username (DM target)
  if (target.startsWith("@")) {
    return target.slice(1).trim();
  }

  // #board-name stays as-is (group target)
  return target;
}

/**
 * Returns true if the raw input looks like a valid PulseBoard target
 * before normalization.
 */
export function looksLikePulseBoardTarget(input: string): boolean {
  const cleaned = input.trim().replace(/^pulseboard:/i, "").trim();
  if (!cleaned) {
    return false;
  }
  // Board: starts with #
  if (cleaned.startsWith("#")) {
    return cleaned.length > 1;
  }
  // Direct: starts with @ or is a plain alphanumeric username
  if (cleaned.startsWith("@")) {
    return cleaned.length > 1;
  }
  // Plain username: letters, digits, underscores, hyphens, dots
  return /^[\w.\-]+$/.test(cleaned);
}

/**
 * Returns true when the normalized target refers to a board (group).
 */
export function isBoardTarget(normalizedTarget: string): boolean {
  return normalizedTarget.startsWith("#");
}

/**
 * Extract the board name from a normalized board target (strips leading `#`).
 */
export function boardNameFromTarget(normalizedTarget: string): string {
  return normalizedTarget.startsWith("#") ? normalizedTarget.slice(1) : normalizedTarget;
}

