import {
  buildChannelOutboundSessionRoute,
  stripChannelTargetPrefix,
  type ChannelOutboundSessionRouteParams,
} from "openclaw/plugin-sdk/core";
import { isBoardTarget, normalizePulseBoardTarget } from "./normalize.js";

export function resolvePulseBoardOutboundSessionRoute(
  params: ChannelOutboundSessionRouteParams,
) {
  // Strip "pulseboard:" prefix if present, then normalize
  const stripped = stripChannelTargetPrefix(params.target, "pulseboard");
  if (!stripped) {
    return null;
  }
  const target = normalizePulseBoardTarget(stripped);
  if (!target) {
    return null;
  }

  const isBoard = isBoardTarget(target);
  const chatType = isBoard ? "group" : "direct";
  const address = `pulseboard:${target}`;

  return buildChannelOutboundSessionRoute({
    cfg: params.cfg,
    agentId: params.agentId,
    channel: "pulseboard",
    accountId: params.accountId,
    peer: {
      kind: "direct", // use "direct" peer kind for both; chatType distinguishes groups
      id: target,
    },
    chatType,
    from: address,
    to: address,
  });
}

