import { boardNameFromTarget, isBoardTarget } from "./normalize.js";
import { DEFAULT_PULSEBOARD_BASE_URL } from "./types.js";

export interface PulseBoardSendResult {
  messageId: string;
}

/**
 * Send a text message to a PulseBoard target via the REST API.
 *
 * Routing:
 *  - Board target (`#board-name`) → POST /api/boards/{boardName}/messages
 *  - User  target (`username`)    → POST /api/direct-messages
 */
export async function sendPulseBoardMessage(params: {
  apiKey: string;
  baseUrl?: string;
  /** Normalized target: `#board-name` or `username` */
  target: string;
  text: string;
}): Promise<PulseBoardSendResult> {
  const base = (params.baseUrl ?? DEFAULT_PULSEBOARD_BASE_URL).replace(/\/+$/, "");
  const isBoard = isBoardTarget(params.target);

  let url: string;
  let body: Record<string, string>;

  if (isBoard) {
    const boardName = boardNameFromTarget(params.target);
    url = `${base}/api/boards/${encodeURIComponent(boardName)}/messages`;
    body = { text: params.text };
  } else {
    url = `${base}/api/direct-messages`;
    body = { to: params.target, text: params.text };
  }

  const resp = await fetch(url, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${params.apiKey}`,
    },
    body: JSON.stringify(body),
  });

  if (!resp.ok) {
    throw new Error(`PulseBoard API error: ${resp.status} ${resp.statusText}`);
  }

  const data = (await resp.json()) as { id?: unknown };
  return { messageId: String(data.id ?? `pb-${Date.now()}`) };
}

/** Inbound message shape returned by the polling endpoint. */
export interface PulseBoardInboundMessage {
  id: string;
  /** "dm" or "board" */
  type: string;
  /** Sender username */
  from: string;
  /** Board name (only present when type === "board") */
  board?: string;
  text: string;
  /** Unix timestamp in seconds */
  ts: number;
}

/** Response shape from GET /api/messages/poll */
interface PollResponse {
  messages: PulseBoardInboundMessage[];
  nextCursor: string | null;
}

/**
 * Long-poll for new messages.  Returns the next cursor and any messages
 * that arrived since the previous cursor.
 */
export async function pollPulseBoardMessages(params: {
  apiKey: string;
  baseUrl?: string;
  cursor: string | null;
  signal: AbortSignal;
}): Promise<{ messages: PulseBoardInboundMessage[]; nextCursor: string | null }> {
  const base = (params.baseUrl ?? DEFAULT_PULSEBOARD_BASE_URL).replace(/\/+$/, "");
  const qs = params.cursor ? `?cursor=${encodeURIComponent(params.cursor)}` : "";
  const url = `${base}/api/messages/poll${qs}`;

  const resp = await fetch(url, {
    headers: { Authorization: `Bearer ${params.apiKey}` },
    signal: params.signal,
  });

  if (!resp.ok) {
    throw new Error(`PulseBoard poll error: ${resp.status} ${resp.statusText}`);
  }

  const data = (await resp.json()) as PollResponse;
  return {
    messages: Array.isArray(data.messages) ? data.messages : [],
    nextCursor: data.nextCursor ?? null,
  };
}

