import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import {
  createScopedDmSecurityResolver,
  createTopLevelChannelConfigAdapter,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { createChannelPairingController } from "openclaw/plugin-sdk/channel-pairing";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import {
  buildPassiveChannelStatusSummary,
  buildTrafficStatusSummary,
} from "openclaw/plugin-sdk/extension-shared";
import { createComputedAccountStatusAdapter } from "openclaw/plugin-sdk/status-helpers";
import {
  DEFAULT_ACCOUNT_ID,
  buildChannelConfigSchema,
  collectStatusIssuesFromLastError,
  createDefaultChannelRuntimeState,
  createPreCryptoDirectDmAuthorizer,
  dispatchInboundDirectDmWithRuntime,
  formatPairingApproveHint,
  resolveInboundDirectDmAccessWithRuntime,
  type ChannelPlugin,
} from "../runtime-api.js";
import { PulseBoardConfigSchema } from "./config-schema.js";
import {
  boardNameFromTarget,
  isBoardTarget,
  looksLikePulseBoardTarget,
  normalizePulseBoardTarget,
} from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { pollPulseBoardMessages, sendPulseBoardMessage } from "./send.js";
import { resolvePulseBoardOutboundSessionRoute } from "./session-route.js";
import { pulseBoardSetupAdapter, pulseBoardSetupWizard } from "./setup-surface.js";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
  type ResolvedPulseBoardAccount,
} from "./types.js";

// Pairing DM notification: send via API to the requesting user
const activeSenders = new Map<string, { apiKey: string; baseUrl: string }>();

function isSenderAllowed(senderId: string, allowFrom: string[]): boolean {
  const normalized = senderId.trim().toLowerCase();
  for (const entry of allowFrom) {
    const e = String(entry).trim().toLowerCase();
    if (e === "*" || e === normalized) {
      return true;
    }
  }
  return false;
}

const resolveGlobalDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  approveHint: formatPairingApproveHint("pulseboard"),
  normalizeEntry: (raw) => raw.trim().replace(/^@/, "").toLowerCase(),
});

const pulseBoardConfigAdapter = createTopLevelChannelConfigAdapter<ResolvedPulseBoardAccount>({
  sectionKey: "pulseboard",
  resolveAccount: (cfg) => resolvePulseBoardAccount({ cfg }),
  listAccountIds: listPulseBoardAccountIds,
  defaultAccountId: resolveDefaultPulseBoardAccountId,
  deleteMode: "clear-fields",
  clearBaseFields: ["name", "defaultAccount", "apiKey", "baseUrl", "dmPolicy", "allowFrom"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom
      .map((entry) => String(entry).trim().replace(/^@/, ""))
      .filter(Boolean),
});

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin(
  {
    base: {
      id: "pulseboard",
      meta: {
        id: "pulseboard",
        label: "PulseBoard",
        selectionLabel: "PulseBoard",
        docsPath: "/channels/pulseboard",
        docsLabel: "pulseboard",
        blurb: "Real-time bulletin board platform with named boards and direct messages",
        order: 60,
      },
      capabilities: {
        chatTypes: ["direct", "group"],
        media: false,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: buildChannelConfigSchema(PulseBoardConfigSchema),
      setup: pulseBoardSetupAdapter,
      setupWizard: pulseBoardSetupWizard,
      config: {
        ...pulseBoardConfigAdapter,
        isConfigured: (account) => account.configured,
        describeAccount: (account) =>
          describeAccountSnapshot({
            account,
            configured: account.configured,
            extra: {
              baseUrl: account.baseUrl,
            },
          }),
      },
      messaging: {
        normalizeTarget: (target) => normalizePulseBoardTarget(target),
        targetResolver: {
          looksLikeId: (input) => looksLikePulseBoardTarget(input),
          hint: "<#board-name or @username or username>",
        },
        resolveOutboundSessionRoute: (params) =>
          resolvePulseBoardOutboundSessionRoute(params),
      },
      status: {
        ...createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
          defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
          collectStatusIssues: (accounts) =>
            collectStatusIssuesFromLastError("pulseboard", accounts),
          buildChannelSummary: ({ snapshot }) =>
            buildPassiveChannelStatusSummary(snapshot, {
              baseUrl: (snapshot as { baseUrl?: string }).baseUrl ?? null,
            }),
          resolveAccountSnapshot: ({ account, runtime }) => ({
            accountId: account.accountId,
            name: account.name,
            enabled: account.enabled,
            configured: account.configured,
            extra: {
              baseUrl: account.baseUrl,
              ...buildTrafficStatusSummary(runtime),
            },
          }),
        }),
      },
      gateway: {
        startAccount: async (ctx) => {
          const account = ctx.account;
          ctx.setStatus({ accountId: account.accountId });
          ctx.log?.info(
            `[${account.accountId}] starting PulseBoard provider (baseUrl: ${account.baseUrl})`,
          );

          if (!account.configured) {
            throw new Error("PulseBoard API key not configured");
          }

          const runtime = getPulseBoardRuntime();

          const pairing = createChannelPairingController({
            core: runtime,
            channel: "pulseboard",
            accountId: account.accountId,
          });

          // Track the active account credentials for outbound pairing notifications
          activeSenders.set(account.accountId, {
            apiKey: account.apiKey,
            baseUrl: account.baseUrl,
          });

          const resolveInboundAccess = async (senderId: string, rawBody: string) =>
            resolveInboundDirectDmAccessWithRuntime({
              cfg: ctx.cfg,
              channel: "pulseboard",
              accountId: account.accountId,
              dmPolicy: account.config.dmPolicy ?? "pairing",
              allowFrom: account.config.allowFrom,
              senderId,
              rawBody,
              isSenderAllowed,
              runtime: {
                shouldComputeCommandAuthorized:
                  runtime.channel.commands.shouldComputeCommandAuthorized,
                resolveCommandAuthorizedFromAuthorizers:
                  runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
              },
            });

          const authorizeSender = createPreCryptoDirectDmAuthorizer({
            resolveAccess: async (senderId) => resolveInboundAccess(senderId, ""),
            issuePairingChallenge: async ({ senderId, reply }) => {
              await pairing.issueChallenge({
                senderId,
                senderIdLine: `Your PulseBoard username: ${senderId}`,
                sendPairingReply: reply,
                onCreated: () => {
                  ctx.log?.debug?.(
                    `[${account.accountId}] pulseboard pairing request sender=${senderId}`,
                  );
                },
                onReplyError: (err) => {
                  ctx.log?.warn?.(
                    `[${account.accountId}] pulseboard pairing reply failed for ${senderId}: ${String(err)}`,
                  );
                },
              });
            },
            onBlocked: ({ senderId, reason }) => {
              ctx.log?.debug?.(
                `[${account.accountId}] blocked PulseBoard sender ${senderId} (${reason})`,
              );
            },
          });

          // Polling loop — runs until the AbortController is triggered via stop()
          const abortController = new AbortController();
          let cursor: string | null = null;

          const pollLoop = async () => {
            while (!abortController.signal.aborted) {
              try {
                const { messages, nextCursor } = await pollPulseBoardMessages({
                  apiKey: account.apiKey,
                  baseUrl: account.baseUrl,
                  cursor,
                  signal: abortController.signal,
                });

                if (nextCursor) {
                  cursor = nextCursor;
                }

                for (const msg of messages) {
                  if (abortController.signal.aborted) {
                    break;
                  }

                  const senderId = msg.from;

                  // Pre-crypto authorization check for DMs only
                  if (msg.type === "dm") {
                    const authResult = await authorizeSender({
                      senderId,
                      reply: async (text) => {
                        await sendPulseBoardMessage({
                          apiKey: account.apiKey,
                          baseUrl: account.baseUrl,
                          target: senderId,
                          text,
                        });
                      },
                    });
                    if (authResult !== "allow") {
                      continue;
                    }
                  }

                  const resolvedAccess = await resolveInboundAccess(senderId, msg.text);
                  if (msg.type === "dm" && resolvedAccess.access.decision !== "allow") {
                    ctx.log?.warn?.(
                      `[${account.accountId}] dropping PulseBoard DM after preflight drift (${senderId}, ${resolvedAccess.access.reason})`,
                    );
                    continue;
                  }

                  const isBoard = msg.type === "board";
                  const peerTarget = isBoard ? `#${msg.board ?? "unknown"}` : senderId;
                  const address = `pulseboard:${peerTarget}`;

                  await dispatchInboundDirectDmWithRuntime({
                    cfg: ctx.cfg,
                    runtime,
                    channel: "pulseboard",
                    channelLabel: "PulseBoard",
                    accountId: account.accountId,
                    peer: {
                      kind: "direct",
                      id: peerTarget,
                    },
                    senderId,
                    senderAddress: `pulseboard:${senderId}`,
                    recipientAddress: address,
                    conversationLabel: isBoard ? `#${msg.board ?? "unknown"}` : senderId,
                    rawBody: msg.text,
                    messageId: msg.id,
                    timestamp: msg.ts * 1000,
                    commandAuthorized: resolvedAccess.commandAuthorized,
                    deliver: async (payload) => {
                      const outboundText =
                        payload && typeof payload === "object" && "text" in payload
                          ? String((payload as { text?: string }).text ?? "")
                          : "";
                      if (!outboundText.trim()) {
                        return;
                      }
                      const tableMode = runtime.channel.text.resolveMarkdownTableMode({
                        cfg: ctx.cfg,
                        channel: "pulseboard",
                        accountId: account.accountId,
                      });
                      const converted = runtime.channel.text.convertMarkdownTables(
                        outboundText,
                        tableMode,
                      );
                      await sendPulseBoardMessage({
                        apiKey: account.apiKey,
                        baseUrl: account.baseUrl,
                        target: isBoard ? peerTarget : senderId,
                        text: converted,
                      });
                    },
                    onRecordError: (err) => {
                      ctx.log?.error?.(
                        `[${account.accountId}] failed recording PulseBoard inbound session: ${String(err)}`,
                      );
                    },
                    onDispatchError: (err, info) => {
                      ctx.log?.error?.(
                        `[${account.accountId}] PulseBoard ${info.kind} reply failed: ${String(err)}`,
                      );
                    },
                  });
                }

                // Brief pause between polls to avoid hammering the server
                await new Promise<void>((resolve, reject) => {
                  const timer = setTimeout(resolve, 2000);
                  abortController.signal.addEventListener("abort", () => {
                    clearTimeout(timer);
                    reject(new Error("aborted"));
                  });
                });
              } catch (err) {
                if (abortController.signal.aborted) {
                  break;
                }
                ctx.log?.error?.(
                  `[${account.accountId}] PulseBoard poll error: ${String(err)}`,
                );
                // Back off before retrying
                await new Promise<void>((resolve, reject) => {
                  const timer = setTimeout(resolve, 5000);
                  abortController.signal.addEventListener("abort", () => {
                    clearTimeout(timer);
                    reject(new Error("aborted"));
                  });
                });
              }
            }
          };

          // Start polling in the background — errors are handled inside the loop
          pollLoop().catch((err) => {
            if (!abortController.signal.aborted) {
              ctx.log?.error?.(
                `[${account.accountId}] PulseBoard poll loop exited unexpectedly: ${String(err)}`,
              );
            }
          });

          ctx.log?.info(`[${account.accountId}] PulseBoard provider started`);

          return {
            stop: () => {
              abortController.abort();
              activeSenders.delete(account.accountId);
              ctx.log?.info(`[${account.accountId}] PulseBoard provider stopped`);
            },
          };
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseBoardUsername",
        message: "Your pairing request has been approved!",
        normalizeAllowEntry: (entry) => entry.trim().replace(/^@/, "").toLowerCase(),
        notify: async ({ id, message }) => {
          // Send approval notification to the requesting user
          const creds = activeSenders.get(DEFAULT_ACCOUNT_ID);
          if (creds) {
            await sendPulseBoardMessage({
              apiKey: creds.apiKey,
              baseUrl: creds.baseUrl,
              target: id,
              text: message,
            });
          }
        },
      },
    },
    security: {
      resolveDmPolicy: resolveGlobalDmPolicy,
    },
    outbound: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
      sendText: async ({ cfg, to, text, accountId }) => {
        const core = getPulseBoardRuntime();
        const aid = accountId ?? DEFAULT_ACCOUNT_ID;
        const account = resolvePulseBoardAccount({ cfg, accountId: aid });

        if (!account.configured) {
          throw new Error(`PulseBoard not configured for account ${aid}`);
        }

        const tableMode = core.channel.text.resolveMarkdownTableMode({
          cfg,
          channel: "pulseboard",
          accountId: aid,
        });
        const message = core.channel.text.convertMarkdownTables(text ?? "", tableMode);
        const normalizedTo = normalizePulseBoardTarget(to);

        // For board targets that didn't come with a '#', board names are used as-is
        const target = isBoardTarget(normalizedTo)
          ? normalizedTo
          : normalizedTo;

        const result = await sendPulseBoardMessage({
          apiKey: account.apiKey,
          baseUrl: account.baseUrl,
          target,
          text: message,
        });

        return attachChannelToResult("pulseboard", {
          to: normalizedTo,
          messageId: result.messageId,
        });
      },
    },
  },
);

/**
 * Get the board name from a normalized board target for external use.
 * Re-exported for convenience.
 */
export { boardNameFromTarget, isBoardTarget, normalizePulseBoardTarget } from "./normalize.js";

