    const prompter = createTestWizardPrompter({
      text: vi.fn(async ({ message }: { message: string }) => {
        if (message === "PulseBoard API key") {
          return TEST_API_KEY;
        }
        if (message === "PulseBoard base URL (optional)") {
          return "";
        }
        throw new Error(`Unexpected prompt: ${message}`);
      }) as WizardPrompter["text"],
    });

    const result = await runSetupWizardConfigure({
      configure: pulseBoardConfigure,
      cfg: {} as OpenClawConfig,
      prompter,
      options: {},
    });

    expect(result.accountId).toBe("default");
    expect(result.cfg.channels?.pulseboard?.enabled).toBe(true);
    expect(result.cfg.channels?.pulseboard?.apiKey).toBe(TEST_API_KEY);
  });

  it("configures an API key and custom base URL", async () => {
    const prompter = createTestWizardPrompter({
      text: vi.fn(async ({ message }: { message: string }) => {
        if (message === "PulseBoard API key") {
          return TEST_API_KEY;
        }
        if (message === "PulseBoard base URL (optional)") {
          return TEST_BASE_URL;
        }
        throw new Error(`Unexpected prompt: ${message}`);
      }) as WizardPrompter["text"],
    });

    const result = await runSetupWizardConfigure({
      configure: pulseBoardConfigure,
      cfg: {} as OpenClawConfig,
      prompter,
      options: {},
    });

    expect(result.cfg.channels?.pulseboard?.apiKey).toBe(TEST_API_KEY);
    expect(result.cfg.channels?.pulseboard?.baseUrl).toBe(TEST_BASE_URL);
  });

  it("keeps unresolved SecretRef apiKey without marking account configured", () => {
    const secretRef = { source: "env" as const, provider: "default", id: "PULSEBOARD_API_KEY" };
    const cfg = { channels: { pulseboard: { apiKey: secretRef } } };

