import { describe, expect, it, vi } from "vitest";
import {
  createPluginSetupWizardConfigure,
  createTestWizardPrompter,
  runSetupWizardConfigure,
  type WizardPrompter,
} from "../../../test/helpers/plugins/setup-wizard.js";
import type { OpenClawConfig } from "../runtime-api.js";
import { pulseBoardPlugin } from "./channel.js";
import { pulseBoardSetupWizard } from "./setup-surface.js";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
  DEFAULT_PULSEBOARD_BASE_URL,
} from "./types.js";
import {
  looksLikePulseBoardTarget,
  normalizePulseBoardTarget,
  isBoardTarget,
  boardNameFromTarget,
} from "./normalize.js";

const TEST_API_KEY = "pb-test-api-key-0123456789abcdef";
const TEST_BASE_URL = "https://pb.example.com";

function createConfiguredPulseBoardCfg(
  overrides: Record<string, unknown> = {},
): { channels: { pulseboard: Record<string, unknown> } } {
  return {
    channels: {
      pulseboard: {
        apiKey: TEST_API_KEY,
        ...overrides,
      },
    },
  };
}

const pulseBoardConfigure = createPluginSetupWizardConfigure(pulseBoardPlugin);

function requireLooksLikeId() {
  const looksLikeId = pulseBoardPlugin.messaging?.targetResolver?.looksLikeId;
  if (!looksLikeId) {
    throw new Error("pulseboard messaging.targetResolver.looksLikeId missing");
  }
  return looksLikeId;
}

function requireNormalizeTarget() {
  const normalize = pulseBoardPlugin.messaging?.normalizeTarget;
  if (!normalize) {
    throw new Error("pulseboard messaging.normalizeTarget missing");
  }
  return normalize;
}

function requireResolveDmPolicy() {
  const resolveDmPolicy = pulseBoardPlugin.security?.resolveDmPolicy;
  if (!resolveDmPolicy) {
    throw new Error("pulseboard security.resolveDmPolicy missing");
  }
  return resolveDmPolicy;
}

// ---------------------------------------------------------------------------
// Plugin metadata
// ---------------------------------------------------------------------------
describe("pulseBoardPlugin", () => {
  describe("meta", () => {
    it("has correct id", () => {
      expect(pulseBoardPlugin.id).toBe("pulseboard");
    });

    it("has required meta fields", () => {
      expect(pulseBoardPlugin.meta.label).toBe("PulseBoard");
      expect(pulseBoardPlugin.meta.docsPath).toBe("/channels/pulseboard");
      expect(pulseBoardPlugin.meta.blurb).toContain("bulletin board");
    });
  });

  // ---------------------------------------------------------------------------
  // Capabilities
  // ---------------------------------------------------------------------------
  describe("capabilities", () => {
    it("supports direct messages", () => {
      expect(pulseBoardPlugin.capabilities.chatTypes).toContain("direct");
    });

    it("supports group (board) messages", () => {
      expect(pulseBoardPlugin.capabilities.chatTypes).toContain("group");
    });

    it("does not support media", () => {
      expect(pulseBoardPlugin.capabilities.media).toBe(false);
    });
  });

  // ---------------------------------------------------------------------------
  // Config adapter
  // ---------------------------------------------------------------------------
  describe("config adapter", () => {
    it("listAccountIds returns empty array for unconfigured", () => {
      const cfg = { channels: {} };
      expect(pulseBoardPlugin.config.listAccountIds(cfg)).toEqual([]);
    });

    it("listAccountIds returns default for configured", () => {
      const cfg = createConfiguredPulseBoardCfg();
      expect(pulseBoardPlugin.config.listAccountIds(cfg)).toContain("default");
    });

    it("isConfigured returns false when apiKey is absent", () => {
      const cfg = { channels: { pulseboard: { enabled: true } } };
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      expect(pulseBoardPlugin.config.isConfigured(account)).toBe(false);
    });

    it("isConfigured returns true when apiKey is present", () => {
      const cfg = createConfiguredPulseBoardCfg();
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      expect(pulseBoardPlugin.config.isConfigured(account)).toBe(true);
    });
  });

  // ---------------------------------------------------------------------------
  // Messaging / target normalization
  // ---------------------------------------------------------------------------
  describe("messaging", () => {
    describe("looksLikeId", () => {
      it("recognizes board target (#board)", () => {
        const looksLikeId = requireLooksLikeId();
        expect(looksLikeId("#general")).toBe(true);
        expect(looksLikeId("#tech-news")).toBe(true);
      });

      it("recognizes @username target", () => {
        const looksLikeId = requireLooksLikeId();
        expect(looksLikeId("@alice")).toBe(true);
      });

      it("recognizes plain username target", () => {
        const looksLikeId = requireLooksLikeId();
        expect(looksLikeId("alice")).toBe(true);
        expect(looksLikeId("bob_123")).toBe(true);
      });

      it("rejects empty string", () => {
        const looksLikeId = requireLooksLikeId();
        expect(looksLikeId("")).toBe(false);
        expect(looksLikeId("  ")).toBe(false);
      });

      it("rejects bare # with nothing after", () => {
        const looksLikeId = requireLooksLikeId();
        expect(looksLikeId("#")).toBe(false);
      });
    });

    describe("normalizeTarget", () => {
      it("strips @ from DM target", () => {
        const normalize = requireNormalizeTarget();
        expect(normalize("@alice")).toBe("alice");
        expect(normalize("  @bob  ")).toBe("bob");
      });

      it("preserves # for board targets", () => {
        const normalize = requireNormalizeTarget();
        expect(normalize("#general")).toBe("#general");
        expect(normalize("  #tech-news  ")).toBe("#tech-news");
      });

      it("strips pulseboard: channel prefix", () => {
        const normalize = requireNormalizeTarget();
        expect(normalize("pulseboard:#general")).toBe("#general");
        expect(normalize("pulseboard:alice")).toBe("alice");
        expect(normalize("pulseboard:@alice")).toBe("alice");
      });

      it("returns plain username unchanged", () => {
        const normalize = requireNormalizeTarget();
        expect(normalize("alice")).toBe("alice");
      });
    });
  });

  // ---------------------------------------------------------------------------
  // Outbound
  // ---------------------------------------------------------------------------
  describe("outbound", () => {
    it("has direct delivery mode", () => {
      expect(pulseBoardPlugin.outbound?.deliveryMode).toBe("direct");
    });

    it("has 4000-character text chunk limit", () => {
      expect(pulseBoardPlugin.outbound?.textChunkLimit).toBe(4000);
    });
  });

  // ---------------------------------------------------------------------------
  // Pairing
  // ---------------------------------------------------------------------------
  describe("pairing", () => {
    it("has correct id label", () => {
      expect(pulseBoardPlugin.pairing?.idLabel).toBe("pulseBoardUsername");
    });

    it("normalizes allow entries by stripping @ and lowercasing", () => {
      const normalize = pulseBoardPlugin.pairing?.normalizeAllowEntry;
      if (!normalize) throw new Error("pairing normalizeAllowEntry missing");
      expect(normalize("@Alice")).toBe("alice");
      expect(normalize("  BOB  ")).toBe("bob");
    });
  });

  // ---------------------------------------------------------------------------
  // Security / DM policy
  // ---------------------------------------------------------------------------
  describe("security", () => {
    it("resolves dm policy from config", () => {
      const resolveDmPolicy = requireResolveDmPolicy();

      const cfg = createConfiguredPulseBoardCfg({
        dmPolicy: "allowlist",
        allowFrom: ["alice"],
      });
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      const result = resolveDmPolicy({ cfg, account });

      expect(result).not.toBeNull();
      expect(result?.policy).toBe("allowlist");
      expect(result?.allowFrom).toEqual(["alice"]);
    });

    it("defaults to pairing when no dmPolicy set", () => {
      const resolveDmPolicy = requireResolveDmPolicy();
      const cfg = createConfiguredPulseBoardCfg();
      const account = pulseBoardPlugin.config.resolveAccount(cfg, "default");
      const result = resolveDmPolicy({ cfg, account });
      expect(result?.policy).toBe("pairing");
    });
  });

  // ---------------------------------------------------------------------------
  // Status
  // ---------------------------------------------------------------------------
  describe("status", () => {
    it("has default runtime for the default account", () => {
      expect(pulseBoardPlugin.status?.defaultRuntime).toMatchObject({
        accountId: "default",
        running: false,
        lastStartAt: null,
        lastStopAt: null,
        lastError: null,
      });
    });
  });
});

// ---------------------------------------------------------------------------
// normalize helpers (unit tests for normalize.ts)
// ---------------------------------------------------------------------------
describe("PulseBoard normalize helpers", () => {
  describe("isBoardTarget", () => {
    it("returns true for board targets", () => {
      expect(isBoardTarget("#general")).toBe(true);
      expect(isBoardTarget("#tech-news")).toBe(true);
    });

    it("returns false for DM targets", () => {
      expect(isBoardTarget("alice")).toBe(false);
      expect(isBoardTarget("@alice")).toBe(false);
    });
  });

  describe("boardNameFromTarget", () => {
    it("strips leading # from board target", () => {
      expect(boardNameFromTarget("#general")).toBe("general");
      expect(boardNameFromTarget("#tech-news")).toBe("tech-news");
    });

    it("returns target unchanged when no # present", () => {
      expect(boardNameFromTarget("alice")).toBe("alice");
    });
  });

  describe("normalizePulseBoardTarget (standalone)", () => {
    it("strips @ from usernames", () => {
      expect(normalizePulseBoardTarget("@alice")).toBe("alice");
    });

    it("keeps # for boards", () => {
      expect(normalizePulseBoardTarget("#news")).toBe("#news");
    });

    it("strips pulseboard: prefix before normalizing", () => {
      expect(normalizePulseBoardTarget("PULSEBOARD:@alice")).toBe("alice");
      expect(normalizePulseBoardTarget("pulseboard:#news")).toBe("#news");
    });
  });

  describe("looksLikePulseBoardTarget (standalone)", () => {
    it("accepts board, @user, and plain username", () => {
      expect(looksLikePulseBoardTarget("#board")).toBe(true);
      expect(looksLikePulseBoardTarget("@user")).toBe(true);
      expect(looksLikePulseBoardTarget("user")).toBe(true);
    });

    it("rejects empty or bare sigil", () => {
      expect(looksLikePulseBoardTarget("")).toBe(false);
      expect(looksLikePulseBoardTarget("#")).toBe(false);
      expect(looksLikePulseBoardTarget("@")).toBe(false);
    });
  });
});

// ---------------------------------------------------------------------------
// Account helpers (unit tests for types.ts)
// ---------------------------------------------------------------------------
describe("PulseBoard account helpers", () => {
  describe("listPulseBoardAccountIds", () => {
    it("returns empty array when not configured", () => {
      const cfg = { channels: {} };
      expect(listPulseBoardAccountIds(cfg)).toEqual([]);
    });

    it("returns empty array when section exists but no apiKey", () => {
      const cfg = { channels: { pulseboard: { enabled: true } } };
      expect(listPulseBoardAccountIds(cfg)).toEqual([]);
    });

    it("returns default when apiKey is configured", () => {
      const cfg = createConfiguredPulseBoardCfg();
      expect(listPulseBoardAccountIds(cfg)).toEqual(["default"]);
    });

    it("respects configured defaultAccount", () => {
      const cfg = createConfiguredPulseBoardCfg({ defaultAccount: "work" });
      expect(listPulseBoardAccountIds(cfg)).toEqual(["work"]);
    });
  });

  describe("resolveDefaultPulseBoardAccountId", () => {
    it("returns default when configured", () => {
      const cfg = createConfiguredPulseBoardCfg();
      expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("default");
    });

    it("returns default when not configured", () => {
      const cfg = { channels: {} };
      expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("default");
    });
  });

  describe("resolvePulseBoardAccount", () => {
    it("resolves configured account", () => {
      const cfg = createConfiguredPulseBoardCfg({
        name: "Test Bot",
        baseUrl: TEST_BASE_URL,
        dmPolicy: "pairing",
      });
      const account = resolvePulseBoardAccount({ cfg });

      expect(account.accountId).toBe("default");
      expect(account.name).toBe("Test Bot");
      expect(account.enabled).toBe(true);
      expect(account.configured).toBe(true);
      expect(account.apiKey).toBe(TEST_API_KEY);
      expect(account.baseUrl).toBe(TEST_BASE_URL);
    });

    it("resolves unconfigured account with defaults", () => {
      const cfg = { channels: {} };
      const account = resolvePulseBoardAccount({ cfg });

      expect(account.accountId).toBe("default");
      expect(account.enabled).toBe(true);
      expect(account.configured).toBe(false);
      expect(account.apiKey).toBe("");
      expect(account.baseUrl).toBe(DEFAULT_PULSEBOARD_BASE_URL);
    });

    it("handles disabled channel", () => {
      const cfg = createConfiguredPulseBoardCfg({ enabled: false });
      const account = resolvePulseBoardAccount({ cfg });

      expect(account.enabled).toBe(false);
      expect(account.configured).toBe(true);
    });

    it("respects custom accountId parameter", () => {
      const cfg = createConfiguredPulseBoardCfg();
      const account = resolvePulseBoardAccount({ cfg, accountId: "custom" });
      expect(account.accountId).toBe("custom");
    });

    it("does not treat unresolved SecretRef apiKey as configured", () => {
      const secretRef = { source: "env" as const, provider: "default", id: "PULSEBOARD_API_KEY" };
      const cfg = { channels: { pulseboard: { apiKey: secretRef } } };
      const account = resolvePulseBoardAccount({ cfg });

      expect(account.configured).toBe(false);
      expect(account.apiKey).toBe("");
      expect(account.config.apiKey).toEqual(secretRef);
    });
  });
});

