// Setup wizard
// ---------------------------------------------------------------------------
describe("pulseboard setup wizard", () => {
  it("configures an API key", async () => {
    const prompter = createTestWizardPrompter({
      text: vi.fn(async ({ message }: { message: string }) => {
        if (message === "PulseBoard API key") {
